func newAuthCmd(flags *rootFlags) *cobra.Command {
	cmd := &cobra.Command{
		Use:   "auth",
		Short: "Manage authentication for Youtube Data",
	}

	cmd.AddCommand(newAuthSetupCmd(flags))
	cmd.AddCommand(newAuthLoginCmd(flags))
	cmd.AddCommand(newAuthStatusCmd(flags))
	cmd.AddCommand(newAuthLogoutCmd(flags))

	return cmd
}

// newAuthSetupCmd prints concrete steps for registering an OAuth app and
// obtaining client credentials. Side-effect rule: print by default, --launch
// to open the registration URL, short-circuit when the verifier is running.
func newAuthSetupCmd(_ *rootFlags) *cobra.Command {
	var launch bool
	cmd := &cobra.Command{
		Use:     "setup",
		Short:   "Print steps for registering an OAuth desktop app (use --launch to open the URL)",
		Example: "  youtube-pp-cli auth setup\n  youtube-pp-cli auth setup --launch",
		RunE: func(cmd *cobra.Command, args []string) error {
			w := cmd.OutOrStdout()
			// PATCH: Point setup guidance at Google OAuth desktop credentials used by this CLI.
			launchURL := "https://console.cloud.google.com/apis/credentials"
			fmt.Fprintln(w, "Create a Google OAuth 2.0 Client ID with application type Desktop app:")
			fmt.Fprintf(w, "  %s\n", launchURL)
			fmt.Fprintln(w, "")
			fmt.Fprintln(w, "Then save the downloaded client JSON at:")
			fmt.Fprintf(w, "  %s\n", config.DefaultCredentialsPath)
			fmt.Fprintln(w, "")
			fmt.Fprintln(w, "Then run:")
			fmt.Fprintln(w, "  youtube-pp-cli auth login")
			if !launch {
				return nil
			}
			if cliutil.IsVerifyEnv() {
				fmt.Fprintf(w, "would launch: %s\n", launchURL)
				return nil
			}
			if err := openSetupURL(launchURL); err != nil {
				fmt.Fprintf(cmd.ErrOrStderr(), "could not open browser automatically: %v\nopen this URL manually: %s\n", err, launchURL)
			}
			return nil
		},
	}
	cmd.Flags().BoolVar(&launch, "launch", false, "Open the setup URL in your default browser")
	return cmd
}

// openSetupURL opens url in the OS default browser and returns any error
// from the launch. Distinct from openBrowser (used by `auth login`) because
// `auth setup --launch` prints a manual-fallback message on failure rather
// than silently failing. Per the side-effect rule, the caller short-circuits
// with cliutil.IsVerifyEnv() before this is reached.
func openSetupURL(url string) error {
	var c *exec.Cmd
	switch runtime.GOOS {
	case "darwin":
		c = exec.Command("open", url)
	case "linux":
		c = exec.Command("xdg-open", url)
	case "windows":
		c = exec.Command("rundll32", "url.dll,FileProtocolHandler", url)
	default:
		return fmt.Errorf("unsupported OS: %s", runtime.GOOS)
	}
	return c.Start()
}

func newAuthLoginCmd(flags *rootFlags) *cobra.Command {
	var clientID string
	var clientSecret string
	var port int
	var noBrowser bool

	cmd := &cobra.Command{
		Use:   "login",
		Short: "Authenticate via Google OAuth2 desktop flow",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return err
			}

			scopes := config.DefaultYoutubeScopes()
			// PATCH: Use the official Google OAuth installed-app config from the shared credential file.
			oauthCfg, err := cfg.OAuthConfig(scopes)
			if err != nil {
				if clientID == "" {
					return err
				}
				oauthCfg = config.OAuthConfigFromClient(clientID, clientSecret, scopes)
				fmt.Fprintf(cmd.ErrOrStderr(), "warning: using deprecated --client-id fallback because credentials file could not be read: %v\n", err)
			}

			stateBytes := make([]byte, 16)
			if _, err := rand.Read(stateBytes); err != nil {
				return fmt.Errorf("generating state: %w", err)
			}
			state := hex.EncodeToString(stateBytes)

			listener, err := net.Listen("tcp", fmt.Sprintf("127.0.0.1:%d", port))
			if err != nil {
				return fmt.Errorf("starting callback server: %w", err)
			}
			defer listener.Close()

			redirectURI := fmt.Sprintf("http://127.0.0.1:%d/callback", listener.Addr().(*net.TCPAddr).Port)
			oauthCfg.RedirectURL = redirectURI

			authURL := oauthCfg.AuthCodeURL(state,
				oauth2.AccessTypeOffline,
				oauth2.SetAuthURLParam("prompt", "consent"),
			)
			// PATCH: WSL browser handoff is fragile; always print the URL and support --no-browser.
			out := cmd.OutOrStdout()
			fmt.Fprintf(out, "OAuth callback listening on port %d\n", listener.Addr().(*net.TCPAddr).Port)
			fmt.Fprintln(out, "Open this OAuth consent URL in your browser to authenticate:")
			fmt.Fprintln(out, authURL)
			if noBrowser {
				fmt.Fprintln(out, "Browser auto-open disabled by --no-browser.")
			} else if cliutil.IsVerifyEnv() {
				fmt.Fprintf(out, "would open OAuth URL: %s\n", authURL)
			} else if err := openBrowser(authURL); err != nil {
				fmt.Fprintf(cmd.ErrOrStderr(), "could not open browser automatically: %v\n", err)
			} else {
				fmt.Fprintln(out, "Opened OAuth consent URL in your browser.")
			}
			fmt.Fprintln(out, "Waiting for Google OAuth callback (timeout: 3m0s)...")

			codeCh := make(chan string, 1)
			errCh := make(chan error, 1)

			mux := http.NewServeMux()
			mux.HandleFunc("/callback", func(w http.ResponseWriter, r *http.Request) {
				if r.URL.Query().Get("state") != state {
					errCh <- fmt.Errorf("state mismatch")
					http.Error(w, "State mismatch", http.StatusBadRequest)
					return
				}
				if errMsg := r.URL.Query().Get("error"); errMsg != "" {
					errCh <- fmt.Errorf("auth error: %s", errMsg)
					http.Error(w, errMsg, http.StatusBadRequest)
					return
				}
				code := r.URL.Query().Get("code")
				if code == "" {
					errCh <- fmt.Errorf("no code in callback")
					http.Error(w, "No code", http.StatusBadRequest)
					return
				}
				w.Header().Set("Content-Type", "text/html")
				fmt.Fprint(w, "<html><body><h2>Authentication successful!</h2><p>You can close this tab.</p></body></html>")
				codeCh <- code
			})

			server := &http.Server{Handler: mux}
			go func() { _ = server.Serve(listener) }()

			var code string
			select {
			case code = <-codeCh:
			case err := <-errCh:
				return err
			case <-time.After(3 * time.Minute):
				return fmt.Errorf("authentication timed out after 3 minutes")
			}

			shutdownCtx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
			defer cancel()
			_ = server.Shutdown(shutdownCtx)

			token, err := oauthCfg.Exchange(context.Background(), code)
			if err != nil {
				return fmt.Errorf("exchanging OAuth code for token: %w", err)
			}
			if token.AccessToken == "" {
				return fmt.Errorf("no access token in OAuth response")
			}
			if err := cfg.SaveOAuthToken(token, scopes); err != nil {
				return fmt.Errorf("saving OAuth token: %w", err)
			}

			if flags.asJSON {
				out := map[string]any{
					"authenticated":    true,
					"credentials_path": cfg.CredentialsPath,
					"token_path":       cfg.TokenPath,
					"scopes":           scopes,
				}
				if !token.Expiry.IsZero() {
					out["token_expiry"] = token.Expiry.Format(time.RFC3339)
				}
				return printJSONFiltered(cmd.OutOrStdout(), out, flags)
			}

			if token.Expiry.IsZero() {
				fmt.Fprintf(cmd.ErrOrStderr(), "%s Authentication successful. Token saved to %s. Token expiry not provided.\n", green("OK"), cfg.TokenPath)
			} else {
				fmt.Fprintf(cmd.ErrOrStderr(), "%s Authentication successful. Token saved to %s. Token expires at %s.\n", green("OK"), cfg.TokenPath, token.Expiry.Format(time.RFC3339))
			}
			return nil
		},
	}

	cmd.Flags().StringVar(&clientID, "client-id", os.Getenv("YOUTUBE_CLIENT_ID"), "OAuth2 client ID (deprecated; prefer OAuth desktop client JSON)")
	cmd.Flags().StringVar(&clientSecret, "client-secret", os.Getenv("YOUTUBE_CLIENT_SECRET"), "OAuth2 client secret (deprecated; prefer OAuth desktop client JSON)")
	cmd.Flags().IntVar(&port, "port", 8085, "Local callback server port (0 chooses a free port)")
	cmd.Flags().BoolVar(&noBrowser, "no-browser", false, "Print OAuth URL and wait for callback without opening a browser")

	return cmd
}

func newAuthStatusCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "status",
		Short: "Show authentication status",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return err
			}
			report := buildAuthStatusReport(cmd.Context(), cfg, flags.timeout)
			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), report, flags)
			}
			renderAuthStatus(cmd.OutOrStdout(), report)
			return nil
		},
	}
}

func buildAuthStatusReport(ctx context.Context, cfg *config.Config, timeout time.Duration) map[string]any {
	credentialsStatus := cfg.CredentialsFileStatus()
	tokenStatus := cfg.TokenFileStatus()
	configuredScopes := config.DefaultYoutubeScopes()
	report := map[string]any{
		"authenticated":           false,
		"verified":                false,
		"credentials_path":        cfg.CredentialsPath,
		"token_path":              cfg.TokenPath,
		"credential_file_exists":  credentialsStatus.Exists,
		"token_file_exists":       tokenStatus.Exists,
		"credentials_file":        fileStatusSummary(credentialsStatus),
		"token_file":              fileStatusSummary(tokenStatus),
		"configured_scopes":       configuredScopes,
		"optional_command_scopes": config.OptionalYoutubeScopes(),
	}

	if credentialsStatus.Error != "" {
		report["credentials_error"] = credentialsStatus.Error
	}
	if tokenStatus.Error != "" {
		report["token_error"] = tokenStatus.Error
	}

	if stored, err := cfg.LoadStoredToken(); err == nil {
		tokenScopes := stored.ScopesList()
		if len(tokenScopes) > 0 {
			report["token_scopes"] = tokenScopes
			missingScopes := config.MissingScopes(tokenScopes, configuredScopes)
			if len(missingScopes) > 0 {
				report["missing_scopes"] = missingScopes
				report["scope_hint"] = "run youtube-pp-cli auth login again after granting the configured YouTube scopes"
			}
		} else {
			report["scope_hint"] = "token file does not record granted scopes; run youtube-pp-cli auth login to refresh scope metadata"
		}
	} else if tokenStatus.Exists {
		report["token_error"] = err.Error()
	}

	if credentialsStatus.Exists && tokenStatus.Exists {
		httpClient := &http.Client{Timeout: timeout}
		if timeout == 0 {
			httpClient = http.DefaultClient
		}
		token, tokenScopes, err := cfg.FreshOAuthToken(ctx, httpClient, configuredScopes)
		if err != nil {
			report["auth_error"] = err.Error()
		} else {
			report["authenticated"] = true
			report["verified"] = true
			report["source"] = cfg.AuthSource
			if len(tokenScopes) > 0 {
				report["token_scopes"] = tokenScopes
				if missingScopes := config.MissingScopes(tokenScopes, configuredScopes); len(missingScopes) > 0 {
					report["missing_scopes"] = missingScopes
					report["scope_hint"] = "run youtube-pp-cli auth login again after granting the configured YouTube scopes"
				}
			}
			if !token.Expiry.IsZero() {
				report["token_expiry"] = token.Expiry.Format(time.RFC3339)
			}
		}
	} else if cfg.ManualAuthHeader() != "" {
		report["authenticated"] = true
		report["source"] = cfg.AuthSource
		report["auth_note"] = "using legacy bearer token configuration; shared OAuth token file was not verified"
	} else {
		if !credentialsStatus.Exists {
			report["auth_hint"] = "place OAuth desktop client JSON at credentials_path, then run youtube-pp-cli auth login"
		} else if !tokenStatus.Exists {
			report["auth_hint"] = "run youtube-pp-cli auth login to create the shared token file"
		} else {
			report["auth_hint"] = "run youtube-pp-cli auth login to refresh the shared token file"
		}
	}

	return report
}

func renderAuthStatus(w interface{ Write([]byte) (int, error) }, report map[string]any) {
	fmt.Fprintf(w, "  credential path: %v\n", report["credentials_path"])
	fmt.Fprintf(w, "  token path: %v\n", report["token_path"])
	printAuthCheck(w, "Credentials file", fmt.Sprintf("%v", report["credentials_file"]))
	printAuthCheck(w, "Token file", fmt.Sprintf("%v", report["token_file"]))
	if report["authenticated"] == true {
		fmt.Fprintf(w, "  %s Auth: authenticated\n", green("OK"))
	} else {
		fmt.Fprintf(w, "  %s Auth: not authenticated\n", red("FAIL"))
	}
	if source, ok := report["source"]; ok {
		fmt.Fprintf(w, "  source: %v\n", source)
	}
	if expiry, ok := report["token_expiry"]; ok {
		fmt.Fprintf(w, "  token_expiry: %v\n", expiry)
	}
	fmt.Fprintf(w, "  configured_scopes: %s\n", strings.Join(anyStringSlice(report["configured_scopes"]), ", "))
	if scopes := anyStringSlice(report["token_scopes"]); len(scopes) > 0 {
		fmt.Fprintf(w, "  token_scopes: %s\n", strings.Join(scopes, ", "))
	}
	if missing := anyStringSlice(report["missing_scopes"]); len(missing) > 0 {
		fmt.Fprintf(w, "  %s Missing scopes: %s\n", yellow("WARN"), strings.Join(missing, ", "))
	}
	for _, key := range []string{"auth_error", "token_error", "credentials_error", "scope_hint", "auth_hint", "auth_note"} {
		if v, ok := report[key]; ok {
			fmt.Fprintf(w, "  %s: %v\n", key, v)
		}
	}
}

func printAuthCheck(w interface{ Write([]byte) (int, error) }, label, status string) {
	indicator := green("OK")
	if strings.Contains(status, "missing") || strings.Contains(status, "error") {
		indicator = red("FAIL")
	}
	fmt.Fprintf(w, "  %s %s: %s\n", indicator, label, status)
}

func fileStatusSummary(status config.FileStatus) string {
	if status.Error != "" {
		return "error: " + status.Error
	}
	if status.Exists {
		return "exists"
	}
	return "missing"
}

func anyStringSlice(v any) []string {
	switch vv := v.(type) {
	case []string:
		return vv
	case []any:
		out := make([]string, 0, len(vv))
		for _, item := range vv {
			out = append(out, fmt.Sprintf("%v", item))
		}
		return out
	default:
		return nil
	}
}

func newAuthLogoutCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "logout",
		Short: "Remove stored authentication tokens",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return err
			}
			if err := cfg.ClearTokens(); err != nil {
				return fmt.Errorf("clearing tokens: %w", err)
			}
			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
					"cleared":    true,
					"token_path": cfg.TokenPath,
				}, flags)
			}
			fmt.Fprintf(cmd.ErrOrStderr(), "Logged out. Token removed from %s.\n", cfg.TokenPath)
			return nil
		},
	}
}

func openBrowser(url string) error {
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "darwin":
		cmd = exec.Command("open", url)
	case "linux":
		cmd = exec.Command("xdg-open", url)
	case "windows":
		cmd = exec.Command("rundll32", "url.dll,FileProtocolHandler", url)
	default:
		return fmt.Errorf("unsupported OS: %s", runtime.GOOS)
	}
	return cmd.Start()
}
